/*
 =====================================================================
  Design System & Global Styles
  Visual style: playful, handcrafted, pastel astrology/tarot blog
 =====================================================================
*/

:root {
    /* Core palette from design & supplied spec */
    --color-primary-mint: #C3E9DE;
    --color-primary-lavender: #D2D6F5;

    --color-secondary-green: #1E8A3A;
    --color-secondary-indigo: #2E2E78;

    --color-accent-purple: #A020F0;
    --color-accent-red: #E22A2A;

    --color-neutral-white: #FFFFFF;
    --color-neutral-black: #222222;
    --color-neutral-dark: #444444;

    --color-success: #1E8A3A;
    --color-error: #D32F2F;
    --color-warning: #F9A825;
    --color-info: #1976D2;

    /* Typography scale */
    --font-logo: 'Kalam', 'Comic Sans MS', cursive;
    --font-heading: 'Lora', Georgia, serif;
    --font-body: 'Libre Baskerville', 'Times New Roman', serif;

    --font-size-h1: 30px;
    --font-size-h2: 24px;
    --font-size-h3: 20px;
    --font-size-body: 16px;
    --font-size-small: 13px;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    /* Spacing scale (base unit 8px) */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;

    /* Layout */
    --max-width-container: 1040px;
    --radius-card: 22px;
    --radius-pill: 24px;
    --shadow-soft: 0 3px 6px rgba(0, 0, 0, 0.25);
    --border-dark: 2px solid rgba(34, 34, 34, 0.9);
}

/* Global reset-ish styles */

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-relaxed);
    color: var(--color-neutral-dark);
    background-color: var(--color-primary-lavender);
}

img {
    max-width: 100%;
    height: auto;
}

a {
    color: var(--color-secondary-indigo);
    text-decoration: none;
}

a:hover,
 a:focus {
    text-decoration: underline;
}

.page-wrapper {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

.container {
    width: 100%;
    max-width: var(--max-width-container);
    margin: 0 auto;
    padding: 0 var(--space-2);
}

.site-main {
    flex: 1 0 auto;
    margin-top: var(--space-4);
    margin-bottom: var(--space-5);
}

/*
 =====================================================================
  Header & Watercolor Illustration
 =====================================================================
*/

.site-header {
    position: relative;
    padding-bottom: var(--space-3);
}

.header-illustration {
    background-color: #b9dfe8; /* base sky tone */
    background-image:
        linear-gradient(135deg, rgba(255, 255, 255, 0.85), rgba(210, 214, 245, 0.8)),
        radial-gradient(circle at 10% 20%, rgba(255, 230, 240, 0.9) 0, transparent 55%),
        radial-gradient(circle at 80% 10%, rgba(214, 248, 220, 0.8) 0, transparent 60%);
    background-size: cover;
    background-repeat: no-repeat;
    background-position: center top;
    border-bottom: 3px solid rgba(34, 34, 34, 0.35);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: var(--space-3);
    padding-bottom: var(--space-4);
}

.header-left {
    display: flex;
    align-items: center;
    gap: var(--space-2);
}

/* Menu icon (three horizontal lines, non-interactive) */

.icon-stack {
    display: inline-flex;
    flex-direction: column;
    justify-content: center;
    gap: var(--space-0-5);
}

.menu-line {
    width: 32px;
    height: 4px;
    border-radius: 999px;
    background-color: var(--color-neutral-black);
}

/* Search icon (magnifying glass, non-interactive) */

.icon-search {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    border: 4px solid var(--color-neutral-black);
    position: relative;
}

.icon-search::after {
    content: "";
    position: absolute;
    width: 16px;
    height: 4px;
    border-radius: 999px;
    background-color: var(--color-neutral-black);
    transform: rotate(45deg);
    right: -10px;
    bottom: -2px;
}

.header-center {
    text-align: center;
    flex: 1;
}

.site-logo {
    display: inline-block;
    color: var(--color-secondary-green);
}

.logo-main {
    display: block;
    font-family: var(--font-logo);
    font-size: 40px;
    line-height: var(--line-height-tight);
    font-weight: var(--font-weight-bold);
    letter-spacing: 1px;
}

.logo-tagline {
    display: block;
    margin-top: 4px;
    font-family: var(--font-logo);
    font-size: 20px;
    color: var(--color-accent-red);
}

.header-right {
    min-width: 60px; /* visual balance against header-left */
    text-align: right;
}

/*
 =====================================================================
  Primary Navigation (large mint pill)
 =====================================================================
*/

.primary-nav-wrapper {
    margin-top: -28px; /* overlap onto illustration like in design */
}

.primary-nav-wrapper .container {
    padding-top: 0;
}

.primary-nav {
    list-style: none;
    margin: 0 auto;
    padding: var(--space-2) var(--space-3);
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--space-2);
    background-color: var(--color-primary-mint);
    border-radius: var(--radius-pill);
    border: var(--border-dark);
    box-shadow: var(--shadow-soft);
}

.nav-item a {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-semibold);
    color: var(--color-secondary-indigo);
    font-size: 17px;
    padding: 4px 10px;
}

.nav-item a:hover,
.nav-item a:focus {
    color: var(--color-secondary-green);
    text-decoration: none;
}

/*
 =====================================================================
  Breadcrumb (slimmer mint pill under nav)
 =====================================================================
*/

.breadcrumb-wrapper {
    margin-top: var(--space-2);
}

.breadcrumb-container {
    background-color: var(--color-primary-mint);
    border-radius: var(--radius-pill);
    border: var(--border-dark);
    box-shadow: var(--shadow-soft);
    padding: 10px var(--space-3);
    font-size: var(--font-size-small);
    color: var(--color-secondary-green);
}

.breadcrumb-container a {
    color: var(--color-secondary-green);
    font-weight: var(--font-weight-semibold);
}

/*
 =====================================================================
  Generic Card Styles (for main content, not instantiated in framework)
 =====================================================================
*/

.card {
    background-color: var(--color-neutral-white);
    border-radius: var(--radius-card);
    border: var(--border-dark);
    box-shadow: var(--shadow-soft);
    padding: var(--space-3);
    margin-bottom: var(--space-3);
}

.card h1,
.card h2,
.card h3 {
    font-family: var(--font-heading);
    color: var(--color-accent-purple);
    margin-top: 0;
}

.card h1 {
    font-size: var(--font-size-h1);
}

.card h2 {
    font-size: var(--font-size-h2);
}

.card h3 {
    font-size: var(--font-size-h3);
}

.card p {
    margin-top: 0;
    margin-bottom: var(--space-2);
}

/*
 =====================================================================
  Footer
 =====================================================================
*/

.site-footer {
    background: transparent;
    padding-bottom: var(--space-4);
}

.footer-inner {
    background-color: var(--color-primary-mint);
    border-radius: var(--radius-card);
    border: var(--border-dark);
    box-shadow: var(--shadow-soft);
    padding: var(--space-3) var(--space-3) var(--space-2);
}

.footer-nav {
    margin-bottom: var(--space-2);
}

.footer-links {
    list-style: none;
    padding: 0;
    margin: 0;
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--space-1) var(--space-3);
}

.footer-links a {
    font-family: var(--font-heading);
    font-size: 15px;
    font-weight: var(--font-weight-medium);
    color: var(--color-secondary-indigo);
}

.footer-links a:hover,
.footer-links a:focus {
    color: var(--color-secondary-green);
    text-decoration: none;
}

.footer-meta {
    text-align: center;
    font-size: var(--font-size-small);
    color: var(--color-neutral-black);
}

.footer-year {
    font-weight: var(--font-weight-semibold);
}

/*
 =====================================================================
  Utility classes
 =====================================================================
*/

.text-center {
    text-align: center;
}

.mt-2 {
    margin-top: var(--space-2);
}

.mb-2 {
    margin-bottom: var(--space-2);
}

@media (max-width: 768px) {
    .header-inner {
        flex-direction: row;
        align-items: flex-start;
    }

    .header-center {
        padding: 0 var(--space-2);
    }

    .logo-main {
        font-size: 32px;
    }

    .logo-tagline {
        font-size: 18px;
    }

    .primary-nav {
        padding: var(--space-1) var(--space-2);
    }

    .nav-item a {
        font-size: 15px;
    }

    .footer-inner {
        padding: var(--space-2);
    }
}
